import {BrowserRouter as Router, Route, Routes } from "react-router-dom";
import Projects from "./components/Projects";

function App() {
  return (
    <div className="App">
      <Navbar />
      <div className="project-lists">
        <Router>
          <Routes>
            <Route path="/" element={<Projects/>}></Route>
            <Route></Route>
            <Route></Route>
            <Route></Route>
          </Routes>
        </Router>
      </div>
    </div>
  );
}

export default App;
